import { Fragment, FC } from 'react';

import { SIZE_SMALL } from '#components/Icon/Icon.constants';
import { formatPrice } from '#components/ProductComparisonCommon/helpers/formatPrice';
import StarRating from '#components/StarRating';

import { SPEC_RATING_TOTAL } from './Table.constants';
import {
  ComparisonTable,
  Hero,
  ImageContainer,
  List,
  Price,
  ProductText,
  Cell,
  Key,
  Value,
  ProductTitle,
} from './Table.styles';
import { TableProps } from './Table.types';
import { calculateSpecLength } from './helpers/calculateSpecLength';
import { getLivePrice } from './helpers/getLivePrice';

// i.e., best, rating, and price
const STATIC_CELLS_LENGTH = 3;

const Table: FC<TableProps> = ({ items, livePrices }) => {
  const specLength = calculateSpecLength(items, STATIC_CELLS_LENGTH);

  return (
    <ComparisonTable $columns={items.length} $rows={specLength}>
      {items.map(({ id, image, title, productSpecs, price, best, rating }) => (
        <Fragment key={id}>
          <Hero>
            <ImageContainer>{image}</ImageContainer>
            <ProductTitle>
              <ProductText>{title}</ProductText>
            </ProductTitle>
          </Hero>
          <List>
            <Cell key="best">
              <Key>Best</Key>
              <Value>{best}</Value>
            </Cell>

            <Cell key="rating">
              <Key>Rating</Key>
              <Value>
                <StarRating
                  size={SIZE_SMALL}
                  value={rating}
                  total={SPEC_RATING_TOTAL}
                />
              </Value>
            </Cell>

            <Cell key="price">
              <Price>
                {formatPrice(getLivePrice(id, livePrices) || price)}
              </Price>
            </Cell>

            {productSpecs.map(({ key, value }) => {
              return (
                <Cell key={key}>
                  <Key>{key}</Key>
                  <Value>{value}</Value>
                </Cell>
              );
            })}
          </List>
        </Fragment>
      ))}
    </ComparisonTable>
  );
};

export default Table;
