import Button from '#components/Button';
import { BUTTON_AS_ANCHOR } from '#components/Button/Button.constants';

import { BUY_NOW_TEXT, REVIEW_TEXT } from './CTAs.constants';
import { ButtonGroup, ItemButtons } from './CTAs.styles';
import { Props } from './CTAs.types';
import { getUpdatedLink } from './helpers/getUpdatedLink';

const CTAs = (props: Props) => {
  const { items = [], onReviewClick, livePrices } = props;

  return (
    <ButtonGroup>
      {items.map(({ id, buyNow, readReview }) => (
        <ItemButtons key={id}>
          <Button
            as={BUTTON_AS_ANCHOR}
            variant="secondary"
            href={getUpdatedLink(id, livePrices) || buyNow?.vendorLink}
            target="_blank"
            isExternal={buyNow.isExternal}
          >
            {BUY_NOW_TEXT}
          </Button>
          <Button
            as={BUTTON_AS_ANCHOR}
            variant="tertiary"
            href={readReview.anchorHref}
            target="_blank"
            onClick={onReviewClick}
          >
            {REVIEW_TEXT}
          </Button>
        </ItemButtons>
      ))}
    </ButtonGroup>
  );
};

export default CTAs;
