import { ItemBuilder } from '#components/ProductComparisonCommon/builders/ItemBuilder';
import { Product } from '#components/ProductComparisonCommon/types';

import { Item } from '../ProductComparison.types';

export const productsToItems = (products: Product[]): Item[] => {
  return products.map((product) => {
    return new ItemBuilder()
      .best(product.bestFor)
      .buyNow({
        vendorLink: product.vendorLink,
        isExternal: product.isExternal,
        isAvailable: product.isAvailable,
      })
      .id(product.id)
      .image(product.image)
      .price(product.prettyPrice)
      .rating(product.rating)
      .readReview({
        anchorHref: product.anchorHref,
        anchorId: product.anchorId,
      })
      .title(product.title)
      .productSpecs(product.productSpec)
      .build();
  });
};
