import MockImage from '#components/Image';
import {
  BuyNow,
  Item,
  Review,
  Specs,
} from '#components/ProductComparison/ProductComparison.types';

export class ItemBuilder {
  item = {
    best: '',
    buyNow: {
      vendorLink: '',
      isExternal: true,
      isAvailable: true,
    },
    id: '',
    image: <MockImage />,
    price: '',
    productSpecs: [] as Specs,
    rating: 0,
    readReview: {
      anchorHref: '',
      anchorId: '',
    },
    title: '',
  } as Item;

  best(best: string) {
    this.item.best = best;

    return this;
  }

  buyNow(buyNow: BuyNow) {
    this.item.buyNow = buyNow;

    return this;
  }

  id(id: string) {
    this.item.id = id;

    return this;
  }

  image(image: ReactNode) {
    this.item.image = image;

    return this;
  }

  price(price: string) {
    this.item.price = price;

    return this;
  }

  productSpecs(productSpecs: Specs) {
    this.item.productSpecs = productSpecs;

    return this;
  }

  rating(rating: number) {
    this.item.rating = rating;

    return this;
  }

  readReview(readReview: Review) {
    this.item.readReview = readReview;

    return this;
  }

  title(title: string) {
    this.item.title = title;

    return this;
  }

  build() {
    return this.item;
  }
}