import { Product } from '#components/ProductComparisonCommon/types';

import { collectProductSpecKeys } from './collectProductSpecKeys';
import { normaliseProductSpecs } from './normaliseProductSpecs';
import { productsToItems } from './productsToItems';

export function createSelectedItems(
  selectedItems: string[],
  products: Product[],
) {
  const items = productsToItems(products);

  const comparedItems = items.filter((item) => {
    return selectedItems.includes(item.id);
  });

  const keys = collectProductSpecKeys(comparedItems);

  return comparedItems.map((item) => {
    return {
      ...item,
      productSpecs: normaliseProductSpecs(item.productSpecs, keys),
    };
  });
}
