import { ProductSpec } from '#components/ProductComparisonCommon/types';

export const normaliseProductSpecs = (
  productSpec: ProductSpec[],
  keys: string[],
) => {
  return keys.map((key) => {
    const resultSpec: ProductSpec = {
      key,
      value: null,
    };

    const existingSpec = productSpec.find((spec) => {
      return spec.key === key;
    });

    if (existingSpec) {
      resultSpec.value = existingSpec.value;
    }

    return resultSpec;
  });
};
