import { FC } from 'react';

import { Icon } from '#components/Icon';
import { SIZE_BASE } from '#components/Icon/Icon.constants';
import { ModalPageSpecific } from '#components/Modal';

import CTAs from '../CTAs';

import { CLOSE_BUTTON_LABEL } from './Modal.constants';
import { Boundary, Header, Footer, CloseButton, Title } from './Modal.styles';
import { ModalProps } from './Modal.types';

import CloseSVG from '#icons/close-solid-24.svg';

const Modal: FC<ModalProps> = ({
  children,
  className,
  hideProductModal,
  isHidden,
  items,
  returnFocus,
  livePrices,
}) => {
  const title = 'Compare Models';

  return (
    <ModalPageSpecific
      className={className}
      isHidden={isHidden}
      onBackgroundClick={hideProductModal}
      onEscapeKeyPress={hideProductModal}
      returnFocus={returnFocus}
      role="dialog"
    >
      <Boundary>
        <Header>
          <CloseButton
            title={CLOSE_BUTTON_LABEL}
            aria-label={CLOSE_BUTTON_LABEL}
            onClick={hideProductModal}
            type="button"
          >
            <Icon svg={CloseSVG} size={SIZE_BASE} />
          </CloseButton>
        </Header>

        <Title>{title}</Title>
        {children}
        <Footer>
          <CTAs
            onReviewClick={hideProductModal}
            livePrices={livePrices}
            items={items}
          />
        </Footer>
      </Boundary>
    </ModalPageSpecific>
  );
};

export default Modal;
