import { Item } from '../ProductComparison.types';

export const collectProductSpecKeys = (items: Item[]): string[] => {
  const result = [] as string[];

  items.forEach((product) => {
    const productSpec = product.productSpecs;

    productSpec.forEach((spec) => {
      if (!result.includes(spec.key)) {
        result.push(spec.key);
      }
    });
  });

  return result;
};
